    ('44947f00-96d8-5c23-bd8c-52886702ccdc', 'the', '/ðə/', 'el, la, los, las', 'Article', 'The cat is on the table.', 'a1'),
    ('024cab56-8967-534b-98ad-de0aadab2981', 'be', '/biː/', 'ser, estar', 'Verb', 'I want to be happy.', 'a1'),
