    ('49fb49ac-4a4f-5b88-a16a-1fecb41c6c2d', 'and', '/ænd/', 'y', 'Conjunction', 'Bread and butter.', 'a1'),
    ('90d10fce-d67e-5d41-97c6-e94c852fee06', 'a', '/ə/', 'un, una', 'Article', 'I have a dog.', 'a1'),
    ('ddfc86cc-713e-5934-97a3-2472af07dd73', 'in', '/ɪn/', 'en, dentro de', 'Preposition', 'He is in the room.', 'a1'),
    ('269c37d0-7bb5-522b-9ae1-cfb359b3011e', 'that', '/ðæt/', 'que, ese, esa', 'Conjunction/Pronoun', 'I know that you are right.', 'a1'),
    ('ff4721a0-f270-5b3d-bfdf-157cc849ada1', 'have', '/hæv/', 'tener, haber', 'Verb', 'I have two brothers.', 'a1'),
    ('e7c933fb-0090-5bce-8e34-7f24cf88c587', 'I', '/aɪ/', 'yo', 'Pronoun', 'I like music.', 'a1'),
