    ('94978749-960d-5f25-8438-52005e7927de', 'on', '/ɒn/', 'en, sobre', 'Preposition', 'The book is on the desk.', 'a1'),
    ('b4efa8f0-f06e-518b-8eb9-33803fc48140', 'with', '/wɪð/', 'con', 'Preposition', 'Come with me.', 'a1'),
    ('33bcdeef-0052-5777-8d20-e7b2ebfba11e', 'he', '/hiː/', 'el', 'Pronoun', 'He plays guitar.', 'a1'),
    ('427a4312-83fb-51ad-96c4-6d3fcbd628ad', 'as', '/æz/', 'como, tan', 'Conjunction', 'She works as a teacher.', 'a1'),
    ('1337f351-5310-50c4-9bde-2dea97a285e9', 'you', '/juː/', 'tu, usted, ustedes', 'Pronoun', 'You are my friend.', 'a1'),
    ('0ca3eca3-049b-55f7-8a5f-92ad98887a0a', 'do', '/duː/', 'hacer', 'Verb', 'What do you want?', 'a1'),
    ('f8025fd7-2ad0-5dda-b0b2-64dfe21dafa3', 'at', '/æt/', 'en, a', 'Preposition', 'We meet at noon.', 'a1'),
    ('dee86577-fd34-5de3-855c-b4063a2fb16c', 'this', '/ðɪs/', 'este, esta, esto', 'Pronoun/Adjective', 'This is my house.', 'a1'),
    ('cfd70345-23e9-5049-b0be-ca9608a0ddc9', 'but', '/bʌt/', 'pero', 'Conjunction', 'I tried, but I failed.', 'a1'),
    ('3b4977fd-d484-565e-83d8-7be5fac30f77', 'his', '/hɪz/', 'su, de el', 'Pronoun', 'His name is John.', 'a1'),
    ('9c5871fe-7fbc-5c66-997a-9f24e10e5b83', 'by', '/baɪ/', 'por, junto a', 'Preposition', 'The book was written by her.', 'a1'),
    ('12610fb2-2cad-500f-9d4d-7bcd8c63cd37', 'from', '/frɒm/', 'de, desde', 'Preposition', 'I am from Mexico.', 'a1'),
    ('ebc32708-23c9-5617-8fdd-665a15d24641', 'they', '/ðeɪ/', 'ellos, ellas', 'Pronoun', 'They are coming tomorrow.', 'a1'),
    ('1a0d1ed0-c378-56d0-ac7c-bba59b4d52b5', 'we', '/wiː/', 'nosotros', 'Pronoun', 'We love this city.', 'a1'),
    ('ce345538-0e6f-5811-a5f5-52618424dfec', 'her', '/hɜːr/', 'su, de ella, la', 'Pronoun', 'I gave her the letter.', 'a1'),
    ('6de5435e-1c08-58e9-9874-62ff41a7ad89', 'she', '/ʃiː/', 'ella', 'Pronoun', 'She speaks three languages.', 'a1'),
    ('60ed5c8f-3720-5aa9-8c42-c7a60bbe2c3c', 'or', '/ɔːr/', 'o', 'Conjunction', 'Tea or coffee?', 'a1'),
    ('1f767841-76e2-5daf-a148-45a8135b602a', 'an', '/ən/', 'un, una', 'Article', 'She is an engineer.', 'a1'),
    ('d37d455a-d6eb-5fac-a173-c57a95ca748e', 'will', '/wɪl/', '(futuro), voluntad', 'Auxiliary Verb', 'I will call you later.', 'a1'),
    ('ec08dc30-dd25-59b5-86bc-d01a772d79d0', 'my', '/maɪ/', 'mi, mis', 'Pronoun', 'My car is blue.', 'a1'),
    ('23b4a481-159c-5c49-a014-aa881f2fb5d1', 'one', '/wʌn/', 'uno, una', 'Pronoun/Number', 'One day I will travel the world.', 'a1'),
    ('33da4eca-96a2-5f09-819b-afd03913a39c', 'all', '/ɔːl/', 'todo, todos', 'Pronoun/Adjective', 'All students passed the exam.', 'a1'),
    ('1b872a28-fcac-5d99-8365-46e1c97d2abd', 'would', '/wʊd/', '(condicional)', 'Auxiliary Verb', 'I would like some water.', 'a1'),
    ('4d998518-0ba0-57e3-8c01-bc20ce129c3d', 'there', '/ðɛər/', 'ahi, alla', 'Adverb', 'There is a park nearby.', 'a1'),
    ('627ff3da-5ca8-53f7-83dc-7f429f2a660c', 'their', '/ðɛər/', 'su, sus (de ellos)', 'Pronoun', 'Their house is big.', 'a1'),
    ('6f871e6c-3f97-59d5-9aea-42242d4f17db', 'what', '/wɒt/', 'que, cual', 'Pronoun', 'What is your name?', 'a1'),
    ('dd49f5c0-5876-56bc-868f-718200d689a9', 'so', '/soʊ/', 'asi que, tan', 'Conjunction/Adverb', 'It was late, so I left.', 'a1'),
    ('3c7cb4fd-62c0-5ae6-b83c-08298f31eac6', 'up', '/ʌp/', 'arriba, hacia arriba', 'Adverb/Preposition', 'She looked up at the sky.', 'a1'),
    ('32601027-2aac-5d79-a63c-870db7ef8d9e', 'out', '/aʊt/', 'fuera, afuera', 'Adverb/Preposition', 'He went out the door.', 'a1'),
    ('c9a751d5-99c7-5b93-9823-be49bc095975', 'if', '/ɪf/', 'si (condicional)', 'Conjunction', 'If it rains, we stay home.', 'a1'),
    ('89aa027d-e992-59a4-9c75-95b592f2de87', 'about', '/əˈbaʊt/', 'sobre, acerca de', 'Preposition', 'Tell me about your day.', 'a1'),
    ('086442bb-4ed1-520d-8fc3-9f6589862e4f', 'who', '/huː/', 'quien, que', 'Pronoun', 'Who is that person?', 'a1'),
    ('fff0c7c4-527b-5899-bd51-1918715ea6bb', 'get', '/ɡɛt/', 'obtener, conseguir', 'Verb', 'I need to get some sleep.', 'a1'),
    ('20c3608b-7bde-510a-8fd9-f6a06e60915c', 'which', '/wɪtʃ/', 'cual, que', 'Pronoun', 'Which one do you prefer?', 'a1'),
    ('3bd7a974-b316-5fc6-916f-bc8ecb2e5cf2', 'go', '/ɡoʊ/', 'ir', 'Verb', 'Let''s go to the beach.', 'a1'),
    ('2bd2e21d-fdaa-55b4-bb81-70df4f839a2a', 'me', '/miː/', 'me, a mi', 'Pronoun', 'Give me a chance.', 'a1'),
    ('01bdd1e2-8421-5188-91d4-7d2afc1b5a51', 'when', '/wɛn/', 'cuando', 'Conjunction/Adverb', 'When does the movie start?', 'a1')
INSERT INTO vocab_entries (id, en, ipa, es, type, example, level) VALUES
    ('966aea6b-a728-5d09-bbf1-4de1138632af', 'make', '/meɪk/', 'hacer, fabricar', 'Verb', 'She will make dinner tonight.', 'a1'),
    ('b7a6bc5d-ffa9-51c7-b4b7-4e9ba3c27416', 'can', '/kæn/', 'poder', 'Auxiliary Verb', 'I can swim very well.', 'a1'),
    ('9e168eea-370a-57b4-867e-1c0806493980', 'like', '/laɪk/', 'como, gustar', 'Preposition/Verb', 'I feel like dancing.', 'a1'),
    ('91cb1f3d-0526-5143-a2f8-eabe005d0487', 'time', '/taɪm/', 'tiempo, vez', 'Noun', 'We had a great time.', 'a1'),
    ('31ffb2e5-aead-59a7-8b96-a25b6e9c7158', 'no', '/noʊ/', 'no, ningun', 'Adverb/Adjective', 'There is no milk left.', 'a1'),
    ('37a22632-3681-501e-9eab-8b76e66d1ca7', 'just', '/dʒʌst/', 'solo, apenas', 'Adverb', 'I just arrived home.', 'a1'),
    ('b979e108-279b-5b46-8f99-04aa6cea04bd', 'him', '/hɪm/', 'el, a el, lo', 'Pronoun', 'I told him the truth.', 'a1'),
    ('279b87d9-1cd9-5728-ae32-8a67840013dc', 'know', '/noʊ/', 'saber, conocer', 'Verb', 'I know the answer.', 'a1'),
    ('53bbdc3e-a345-506f-bf64-637eeaf9e8b5', 'take', '/teɪk/', 'tomar, llevar', 'Verb', 'Please take a seat.', 'a1'),
